const row = $input.first().json ?? {};
const leaseText = String(row.default_lease_duration ?? '5 minutes');
const leaseSecondsRaw = Number(row.lease_seconds ?? 300);
const leaseSeconds = Number.isFinite(leaseSecondsRaw) && leaseSecondsRaw > 0 ? leaseSecondsRaw : 300;

const isManualExecution = $execution?.mode === 'manual';
const nowMs = Date.now();
const nowIso = new Date(nowMs).toISOString();

const state = $getWorkflowStaticData('global');
const lastRunIso = state.last_reset_stuck_run_at ?? null;
const lastRunMs = lastRunIso ? Date.parse(lastRunIso) : NaN;
const hasLastRun = Number.isFinite(lastRunMs);
const elapsedSeconds = hasLastRun ? Math.floor((nowMs - lastRunMs) / 1000) : null;

const shouldRunNow = isManualExecution || !hasLastRun || elapsedSeconds >= leaseSeconds;

if (shouldRunNow) {
  state.last_reset_stuck_run_at = nowIso;
}

return [{
  json: {
    default_lease_duration: leaseText,
    lease_seconds: leaseSeconds,
    checked_at: nowIso,
    last_run_at: lastRunIso,
    elapsed_seconds: elapsedSeconds,
    is_manual_execution: isManualExecution,
    should_run_now: shouldRunNow
  }
}];

const row = $input.first().json ?? {};
const base = $('Evaluate Run Window').first().json ?? {};
const parsed = Number(row.reset_count ?? row.reset_stuck_tasks ?? 0);
const resetCount = Number.isFinite(parsed) ? parsed : 0;

return [{
  json: {
    ...base,
    reset_count: resetCount,
    should_alert: resetCount > 0
  }
}];

const item = $input.first().json;

return [{
  json: {
    level: 'WARN',
    message: `reset_stuck_tasks() reset ${item.reset_count} task(s)`,
    source: 'task-scheduler-reset-stuck-monitor',
    metadata: {
      reset_count: item.reset_count,
      checked_at: item.checked_at,
      default_lease_duration: item.default_lease_duration
    }
  }
}];

const item = $input.first().json ?? {};

if (item.should_run_now === false) {
  return [{
    json: {
      message: 'No action: reset check is not due yet',
      reason: 'not_due_yet',
      checked_at: item.checked_at ?? new Date().toISOString(),
      last_run_at: item.last_run_at ?? null,
      elapsed_seconds: item.elapsed_seconds ?? null,
      lease_seconds: item.lease_seconds ?? null,
      default_lease_duration: item.default_lease_duration ?? null
    }
  }];
}

return [{
  json: {
    message: 'No stuck tasks found',
    reason: 'no_resets',
    reset_count: Number(item.reset_count ?? 0),
    checked_at: item.checked_at ?? new Date().toISOString(),
    default_lease_duration: item.default_lease_duration ?? null
  }
}];
